1	interface QuoteItem {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteInput {
9	  customer: { yearsWithMHPCO: number };
10	  items: QuoteItem[];
11	  contractIndex?: number;
12	  firstInsurance?: boolean;
13	}
14	
15	const PROCESSING_FEE = 5;
16	
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const BLOCK_SIZE = 3;
27	const BLOCK_PREMIUM = 60;
28	
29	const CURSE_SURCHARGE_RATE = 0.5;
30	
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	
34	function countByType(items: QuoteItem[]): Map<string, number> {
35	  const counts = new Map<string, number>();
36	  for (const item of items) {
37	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
38	  }
39	  return counts;
40	}
41	
42	function priceGroup(type: string, count: number): number {
43	  return count === BLOCK_SIZE ? BLOCK_PREMIUM : BASE_PREMIUMS[type] * count;
44	}
45	
46	function surchargeFor(
47	  items: QuoteItem[],
48	  applies: (item: QuoteItem) => boolean,
49	  rate: number,
50	): number {
51	  let surcharge = 0;
52	  for (const item of items) {
53	    if (applies(item)) {
54	      surcharge += BASE_PREMIUMS[item.type] * rate;
55	    }
56	  }
57	  return surcharge;
58	}
59	
60	function curseSurchargeFor(items: QuoteItem[]): number {
61	  return surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
62	}
63	
64	function highEnchantmentSurchargeFor(items: QuoteItem[]): number {
65	  return surchargeFor(
66	    items,
67	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
68	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
69	  );
70	}
71	
72	function policyBasePremiumFor(items: QuoteItem[]): number {
73	  const countsByType = countByType(items);
74	
75	  let basePremium = 0;
76	  for (const [type, count] of countsByType) {
77	    basePremium += priceGroup(type, count);
78	  }
79	  return basePremium;
80	}
81	
82	function basePremiumFor(items: QuoteItem[]): number {
83	  return (
84	    policyBasePremiumFor(items) +
85	    curseSurchargeFor(items) +
86	    highEnchantmentSurchargeFor(items)
87	  );
88	}
89	
90	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
91	
92	const LOYALTY_YEARS_THRESHOLD = 2;
93	const LOYALTY_DISCOUNT_RATE = 0.2;
94	
95	function applyLoyaltyDiscount(basePremium: number, yearsWithMHPCO: number): number {
96	  if (yearsWithMHPCO < LOYALTY_YEARS_THRESHOLD) {
97	    return basePremium;
98	  }
99	  return basePremium * (1 - LOYALTY_DISCOUNT_RATE);
100	}
101	
102	export function quote(input: QuoteInput): number {
103	  const policyBasePremium = policyBasePremiumFor(input.items);
104	  const basePremium = basePremiumFor(input.items);
105	  const policyPremium = applyLoyaltyDiscount(basePremium, input.customer.yearsWithMHPCO);
106	  const firstInsuranceSurcharge = input.firstInsurance
107	    ? policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE
108	    : 0;
109	  return policyPremium + firstInsuranceSurcharge + PROCESSING_FEE;
110	}
111	
112	export function claim(input: unknown): number {
113	  return undefined as unknown as number;
114	}
